	spec, err := NewSpeciality(speciality)
	if err != nil {
		return nil, err
	}

	area, err := NewArea(department)
	if err != nil {
		return nil, err
	}

	return &Professor{
		User:       *usr,
		Speciality: spec,
		Department: area,
	}, nil
}

